const mismatches = $input.first().json.mismatches || [];
const today = new Date().toISOString().slice(0, 10);

const lines = mismatches.map(function(m) {
  const name = m.account_name || m.account_id;
  const plan = m.plan_name || 'Unknown Plan';
  const configured = parseFloat(m.configured_fee || 0).toFixed(2);
  const invoiced = parseFloat(m.total_invoiced || 0).toFixed(2);
  const delta = parseFloat(m.delta || 0).toFixed(2);
  const sign = parseFloat(delta) > 0 ? '+' : '';
  return '*' + name + '* (' + m.account_id + ')\n  Plan: ' + plan + '\n  Configured: $' + configured + ' | Invoiced (30d): $' + invoiced + ' | Delta: ' + sign + '$' + delta;
});

const header = ':rotating_light: *Payment Gateway Fee Mismatch Alert* :rotating_light:\n*Date:* ' + today + '\n*Mismatches found:* ' + mismatches.length + '\n';
const body = lines.join('\n\n');
const footer = '\n\n_Source: guesty-data.zuora_analytics | Review mismatches in BigQuery_';

return [{
  json: {
    slack_message: header + '\n' + body + footer,
    mismatch_count: mismatches.length
  }
}];

